1	//! Deterministically measure release work backed by committed Formal AI sessions.
2	//!
3	//! Run with `rust-script scripts/self-hosting-metric.rs --since <tag>`. A commit
4	//! is attributed only when it records both of these Git trailers:
5	//!
6	//! - `Formal-AI-Session: <session-id>`
7	//! - `Formal-AI-Evidence: <repo-relative-path>`
8	//!
9	//! The evidence must exist in that commit and contain both `formal-ai` and the
10	//! recorded session id. Changed lines are additions plus deletions reported by
11	//! `git show --numstat`; merge commits and binary files do not contribute.
12	
13	#![allow(dead_code)]
14	
15	use std::env;
16	use std::fs::{self, OpenOptions};
17	use std::io::Write;
18	use std::path::{Component, Path, PathBuf};
19	use std::process::Command;
20	
21	const SESSION_TRAILER: &str = "Formal-AI-Session";
22	const EVIDENCE_TRAILER: &str = "Formal-AI-Evidence";
23	const DEFAULT_LEDGER: &str = "data/meta/self-hosting-ledger.lino";
24	const DEFAULT_TRAILING_WINDOW: usize = 3;
25	
26	#[derive(Clone, Debug, Eq, PartialEq)]
27	pub struct Measurement {
28	    pub self_authored_lines: u64,
29	    pub changed_lines: u64,
30	    pub self_authored_commits: u64,
31	    pub commits: u64,
32	    pub percentage_basis_points: u64,
33	}
34	
35	#[derive(Clone, Debug, Eq, PartialEq)]
36	pub struct ReleaseRow {
37	    pub tag: String,
38	    pub since: String,
39	    pub until: String,
40	    pub self_authored_lines: u64,
41	    pub changed_lines: u64,
42	    pub self_authored_commits: u64,
43	    pub commits: u64,
44	    pub percentage_basis_points: u64,
45	    pub trailing_window: usize,
46	    pub trailing_percentage_basis_points: u64,
47	}
48	
49	pub fn format_percentage(basis_points: u64) -> String {
50	    format!("{}.{:02}%", basis_points / 100, basis_points % 100)
51	}
52	
53	/// How a malformed evidence record is treated.
54	///
55	/// Issue #810: the `Formal-AI-Evidence` gate (`evidence-check` in
56	/// `.github/workflows/release.yml`) was introduced in 39fdef91, *after* commit
57	/// 10e65ae2 had already merged with an evidence document that never spells out
58	/// its own `Formal-AI-Session` id. Because `record_release` measures
59	/// `<last tag>..HEAD`, that historical commit stayed inside the release range
60	/// forever, `Auto Release` aborted on it every single run (29737218421), and no
61	/// new tag could ever be cut to move the range past it — a permanent deadlock
62	/// that history cannot be edited out of.
63	///
64	/// So the two callers get different policies:
65	///
66	/// - `Strict` — the pull-request gate. New commits must be well formed, and a
67	///   malformed record is a hard error *before* it can reach the default branch.
68	/// - `Lenient` — release recording. A malformed record is reported on stderr and
69	///   the commit simply does not count as self-authored. The metric can only
70	///   under-report, never over-report, so the ratchet stays honest.
71	#[derive(Clone, Copy, Debug, Eq, PartialEq)]
72	pub enum EvidencePolicy {
73	    Strict,
74	    Lenient,
75	}
76	
77	pub fn measure(repo: &Path, since: &str, until: &str) -> Result<Measurement, String> {
78	    measure_with_policy(repo, since, until, EvidencePolicy::Strict)
79	}
80	
81	pub fn measure_with_policy(
82	    repo: &Path,
83	    since: &str,
84	    until: &str,
85	    policy: EvidencePolicy,
86	) -> Result<Measurement, String> {
87	    let range = format!("{since}..{until}");
88	    let output = git(repo, &["rev-list", "--reverse", "--no-merges", &range])?;
89	    let commits = output
90	        .lines()
91	        .filter(|line| !line.is_empty())
92	        .collect::<Vec<_>>();
93	    let mut changed_lines = 0_u64;
94	    let mut self_authored_lines = 0_u64;
95	    let mut self_authored_commits = 0_u64;
96	
97	    for commit in &commits {
98	        let lines = changed_lines_for_commit(repo, commit)?;
99	        changed_lines = changed_lines
100	            .checked_add(lines)
101	            .ok_or_else(|| "changed-line total overflowed u64".to_owned())?;
102	        let attributed = match commit_has_formal_ai_evidence(repo, commit) {
103	            Ok(attributed) => attributed,
104	            Err(error) => match policy {
105	                EvidencePolicy::Strict => return Err(error),
106	                EvidencePolicy::Lenient => {
107	                    eprintln!("warning: not attributing {commit}: {error}");
108	                    false
109	                }
110	            },
111	        };
112	        if attributed {
113	            self_authored_lines = self_authored_lines
114	                .checked_add(lines)
115	                .ok_or_else(|| "self-authored line total overflowed u64".to_owned())?;
116	            self_authored_commits += 1;
117	        }
118	    }
119	
120	    Ok(Measurement {
121	        self_authored_lines,
122	        changed_lines,
123	        self_authored_commits,
124	        commits: commits.len() as u64,
125	        percentage_basis_points: percentage_basis_points(self_authored_lines, changed_lines),
126	    })
127	}
128	
129	fn changed_lines_for_commit(repo: &Path, commit: &str) -> Result<u64, String> {
130	    let output = git(
131	        repo,
132	        &["show", "--format=", "--numstat", "--no-renames", commit],
133	    )?;
134	    output.lines().try_fold(0_u64, |total, line| {
135	        let mut fields = line.split('\t');
136	        let additions = fields.next().unwrap_or_default();
137	        let deletions = fields.next().unwrap_or_default();
138	        if additions == "-" || deletions == "-" {
139	            return Ok(total);
140	        }
141	        let additions = additions
142	            .parse::<u64>()
143	            .map_err(|error| format!("invalid numstat additions in {commit}: {error}"))?;
144	        let deletions = deletions
145	            .parse::<u64>()
146	            .map_err(|error| format!("invalid numstat deletions in {commit}: {error}"))?;
147	        total
148	            .checked_add(additions)
149	            .and_then(|sum| sum.checked_add(deletions))
150	            .ok_or_else(|| format!("changed-line count overflowed in {commit}"))
151	    })
152	}
153	
154	fn commit_has_formal_ai_evidence(repo: &Path, commit: &str) -> Result<bool, String> {
155	    let sessions = trailer_values(repo, commit, SESSION_TRAILER)?;
156	    let evidence_paths = trailer_values(repo, commit, EVIDENCE_TRAILER)?;
157	    if sessions.is_empty() && evidence_paths.is_empty() {
158	        return Ok(false);
159	    }
160	    if sessions.is_empty() || evidence_paths.is_empty() {
161	        return Err(format!(
162	            "commit {commit} must record both {SESSION_TRAILER} and {EVIDENCE_TRAILER}"
163	        ));
164	    }
165	
166	    let mut evidence = Vec::with_capacity(evidence_paths.len());
167	    for path in evidence_paths {
168	        validate_evidence_path(&path)?;
169	        let object = format!("{commit}:{path}");
170	        let content = git(repo, &["show", &object])?;
171	        if !content.to_ascii_lowercase().contains("formal-ai") {
172	            return Err(format!(
173	                "evidence {path} in commit {commit} does not identify formal-ai"
174	            ));
175	        }
176	        evidence.push((path, content));
177	    }
178	
179	    for session in sessions {
180	        if !evidence
181	            .iter()
182	            .any(|(_, content)| content.contains(&session))
183	        {
184	            return Err(format!(
185	                "no committed {EVIDENCE_TRAILER} in {commit} records session {session}"
186	            ));
187	        }
188	    }
189	    Ok(true)
190	}
191	
192	/// Collects `key: value` trailers from a commit message.
193	///
194	/// This deliberately scans the whole commit body instead of using git's
195	/// `%(trailers:key=...)` placeholder. Git only recognises the *last* paragraph
196	/// of a message as the trailer block, so a blank line between two trailers
197	/// makes every trailer above it invisible. Release commit
198	/// 59650f2b45ebebf29ed67d33c9a19c1e82e7c003 separated its `Formal-AI-Session`
199	/// and `Formal-AI-Evidence` trailers with a blank line, git reported only the
200	/// evidence trailer, and the resulting "must record both" error failed the
201	/// whole Auto Release job (issue #796).
202	fn trailer_values(repo: &Path, commit: &str, key: &str) -> Result<Vec<String>, String> {
203	    let body = git(repo, &["show", "-s", "--format=%B", commit])?;
204	    let prefix = format!("{key}:");
205	    Ok(body
206	        .lines()
207	        .filter_map(|line| {
208	            let line = line.trim();
209	            // Trailer keys are case-insensitive per `git interpret-trailers`.
210	            line.get(..prefix.len())
211	                .filter(|candidate| candidate.eq_ignore_ascii_case(&prefix))
212	                .map(|_| line[prefix.len()..].trim())
213	        })
214	        .filter(|value| !value.is_empty())
215	        .map(str::to_owned)
216	        .collect())
217	}
218	
219	fn validate_evidence_path(path: &str) -> Result<(), String> {
220	    let candidate = Path::new(path);
221	    if path.contains(':')
222	        || path.contains('\n')
223	        || candidate.is_absolute()
224	        || candidate
225	            .components()
226	            .any(|component| !matches!(component, Component::Normal(_)))
227	    {
228	        return Err(format!(
229	            "{EVIDENCE_TRAILER} must be a normal repo-relative path: {path}"
230	        ));
231	    }
232	    Ok(())
233	}
234	
235	fn percentage_basis_points(numerator: u64, denominator: u64) -> u64 {
236	    if denominator == 0 {
237	        return 0;
238	    }
239	    let rounded =
240	        (u128::from(numerator) * 10_000 + u128::from(denominator) / 2) / u128::from(denominator);
241	    u64::try_from(rounded).expect("percentage basis points fit in u64")
242	}
243	
244	pub fn record_release(
245	    repo: &Path,
246	    ledger: &Path,
247	    tag: &str,
248	    since: &str,
249	    until: &str,
250	    trailing_window: usize,
251	) -> Result<ReleaseRow, String> {
252	    if trailing_window == 0 {
253	        return Err("trailing window must be greater than zero".to_owned());
254	    }
255	    let rows = read_release_rows(ledger)?;
256	    // Lenient on purpose: see `EvidencePolicy`. The pull-request gate is what
257	    // keeps new commits honest; a release must never be blocked by a commit
258	    // that is already immutable history.
259	    let measurement = measure_with_policy(repo, since, until, EvidencePolicy::Lenient)?;
260	    let until_commitish = format!("{until}^{{commit}}");
261	    let canonical_until = git(repo, &["rev-parse", &until_commitish])?
262	        .trim()
263	        .to_owned();
264	    let mut window_rows = rows
265	        .iter()
266	        .rev()
267	        .take(trailing_window.saturating_sub(1))
268	        .cloned()
269	        .collect::<Vec<_>>();
270	    window_rows.reverse();
271	    let mut row = ReleaseRow {
272	        tag: tag.to_owned(),
273	        since: since.to_owned(),
274	        until: canonical_until,
275	        self_authored_lines: measurement.self_authored_lines,
276	        changed_lines: measurement.changed_lines,
277	        self_authored_commits: measurement.self_authored_commits,
278	        commits: measurement.commits,
279	        percentage_basis_points: measurement.percentage_basis_points,
280	        trailing_window,
281	        trailing_percentage_basis_points: 0,
282	    };
283	    window_rows.push(row.clone());
284	    row.trailing_percentage_basis_points = weighted_percentage(&window_rows);
285	
286	    if let Some(existing) = rows.iter().find(|existing| existing.tag == tag) {
287	        if existing == &row {
288	            return Ok(existing.clone());
289	        }
290	        return Err(format!(
291	            "release {tag} already has a different self-hosting ledger row"
292	        ));
293	    }
294	    if let Some(previous) = rows.last() {
295	        if row.trailing_percentage_basis_points < previous.trailing_percentage_basis_points {
296	            return Err(format!(
297	                "self-hosting ratchet would fall from {} to {} for {tag}",
298	                format_percentage(previous.trailing_percentage_basis_points),
299	                format_percentage(row.trailing_percentage_basis_points)
300	            ));
301	        }
302	    }
303	    append_release_row(ledger, &row)?;
304	    Ok(row)
305	}
306	
307	fn weighted_percentage(rows: &[ReleaseRow]) -> u64 {
308	    let self_authored = rows.iter().map(|row| row.self_authored_lines).sum::<u64>();
309	    let changed = rows.iter().map(|row| row.changed_lines).sum::<u64>();
310	    percentage_basis_points(self_authored, changed)
311	}
312	
313	pub fn read_release_rows(ledger: &Path) -> Result<Vec<ReleaseRow>, String> {
314	    let text = fs::read_to_string(ledger)
315	        .map_err(|error| format!("could not read {}: {error}", ledger.display()))?;
316	    let mut rows = Vec::new();
317	    let mut fields = Vec::new();
318	    for line in text.lines() {
319	        if line.trim() == "release" {
320	            if !fields.is_empty() {
321	                rows.push(parse_release_row(&fields)?);
322	                fields.clear();
323	            }
324	        } else if line.starts_with("    ") {
325	            fields.push(line.trim().to_owned());
326	        }
327	    }
328	    if !fields.is_empty() {
329	        rows.push(parse_release_row(&fields)?);
330	    }
331	    Ok(rows)
332	}
333	
334	fn parse_release_row(fields: &[String]) -> Result<ReleaseRow, String> {
335	    let value = |key: &str| -> Result<String, String> {
336	        let prefix = format!("{key} \"");
337	        fields
338	            .iter()
339	            .find_map(|field| {
340	                field
341	                    .strip_prefix(&prefix)
342	                    .and_then(|value| value.strip_suffix('"'))
343	                    .map(str::to_owned)
344	            })
345	            .ok_or_else(|| format!("release row is missing {key}"))
346	    };
347	    let number = |key: &str| -> Result<u64, String> {
348	        value(key)?
349	            .parse::<u64>()
350	            .map_err(|error| format!("release row has invalid {key}: {error}"))
351	    };
352	    Ok(ReleaseRow {
353	        tag: value("tag")?,
354	        since: value("since")?,
355	        until: value("until")?,
356	        self_authored_lines: number("self_authored_lines")?,
357	        changed_lines: number("changed_lines")?,
358	        self_authored_commits: number("self_authored_commits")?,
359	        commits: number("commits")?,
360	        percentage_basis_points: number("percentage_basis_points")?,
361	        trailing_window: usize::try_from(number("trailing_window")?)
362	            .map_err(|_| "trailing_window does not fit usize".to_owned())?,
363	        trailing_percentage_basis_points: number("trailing_percentage_basis_points")?,
364	    })
365	}
366	
367	fn append_release_row(ledger: &Path, row: &ReleaseRow) -> Result<(), String> {
368	    let mut file = OpenOptions::new()
369	        .append(true)
370	        .open(ledger)
371	        .map_err(|error| format!("could not append {}: {error}", ledger.display()))?;
372	    writeln!(
373	        file,
374	        "  release\n    tag \"{}\"\n    since \"{}\"\n    until \"{}\"\n    \
375	         self_authored_lines \"{}\"\n    changed_lines \"{}\"\n    self_authored_commits \
376	         \"{}\"\n    commits \"{}\"\n    percentage_basis_points \"{}\"\n    trailing_window \
377	         \"{}\"\n    trailing_percentage_basis_points \"{}\"",
378	        row.tag,
379	        row.since,
380	        row.until,
381	        row.self_authored_lines,
382	        row.changed_lines,
383	        row.self_authored_commits,
384	        row.commits,
385	        row.percentage_basis_points,
386	        row.trailing_window,
387	        row.trailing_percentage_basis_points,
388	    )
389	    .map_err(|error| format!("could not append {}: {error}", ledger.display()))
390	}
391	
392	pub fn release_note_for_tag(ledger: &Path, tag: &str) -> Result<String, String> {
393	    let row = read_release_rows(ledger)?
394	        .into_iter()
395	        .find(|row| row.tag == tag)
396	        .ok_or_else(|| format!("self-hosting ledger has no release row for {tag}"))?;
397	    Ok(format!(
398	        "## Self-hosting\n\nFormal AI authored **{}** of this release ({} of {} changed lines). The \
399	         {}-release trailing share is **{}**.",
400	        format_percentage(row.percentage_basis_points),
401	        row.self_authored_lines,
402	        row.changed_lines,
403	        row.trailing_window,
404	        format_percentage(row.trailing_percentage_basis_points),
405	    ))
406	}
407	
408	fn git(repo: &Path, args: &[&str]) -> Result<String, String> {
409	    let output = Command::new("git")
410	        .arg("-C")
411	        .arg(repo)
412	        .args(args)
413	        .output()
414	        .map_err(|error| format!("could not run git {args:?}: {error}"))?;
415	    if !output.status.success() {
416	        return Err(format!(
417	            "git {args:?} failed: {}",
418	            String::from_utf8_lossy(&output.stderr).trim()
419	        ));
420	    }
421	    String::from_utf8(output.stdout).map_err(|error| format!("git output was not UTF-8: {error}"))
422	}
423	
424	#[derive(Debug)]
425	struct Options {
426	    repo: PathBuf,
427	    since: String,
428	    until: String,
429	    ledger: PathBuf,
430	    record_release: Option<String>,
431	    trailing_window: usize,
432	}
433	
434	fn parse_options(args: impl IntoIterator<Item = String>) -> Result<Options, String> {
435	    let mut repo = PathBuf::from(".");
436	    let mut since = None;
437	    let mut until = "HEAD".to_owned();
438	    let mut ledger = PathBuf::from(DEFAULT_LEDGER);
439	    let mut record_release = None;
440	    let mut trailing_window = DEFAULT_TRAILING_WINDOW;
441	    let mut args = args.into_iter();
442	    while let Some(arg) = args.next() {
443	        let value = |args: &mut dyn Iterator<Item = String>| {
444	            args.next().ok_or_else(|| format!("{arg} requires a value"))
445	        };
446	        match arg.as_str() {
447	            "--repo" => repo = PathBuf::from(value(&mut args)?),
448	            "--since" => since = Some(value(&mut args)?),
449	            "--until" => until = value(&mut args)?,
450	            "--ledger" => ledger = PathBuf::from(value(&mut args)?),
451	            "--record-release" => record_release = Some(value(&mut args)?),
452	            "--trailing-window" => {
453	                trailing_window = value(&mut args)?
454	                    .parse::<usize>()
455	                    .map_err(|error| format!("invalid --trailing-window: {error}"))?;
456	            }
457	            "--help" | "-h" => {
458	                return Err(
459	                    "usage: self-hosting-metric.rs --since <tag> [--until <rev>] \
460	                     [--record-release <tag>] [--ledger <path>] [--repo <path>]"
461	                        .to_owned(),
462	                );
463	            }
464	            _ => return Err(format!("unknown argument: {arg}")),
465	        }
466	    }
467	    let since = since.ok_or_else(|| "--since <tag> is required".to_owned())?;
468	    let ledger = if ledger.is_absolute() {
469	        ledger
470	    } else {
471	        repo.join(ledger)
472	    };
473	    Ok(Options {
474	        repo,
475	        since,
476	        until,
477	        ledger,
478	        record_release,
479	        trailing_window,
480	    })
481	}
482	
483	fn run() -> Result<(), String> {
484	    let options = parse_options(env::args().skip(1))?;
485	    let measurement = if let Some(tag) = options.record_release {
486	        let row = record_release(
487	            &options.repo,
488	            &options.ledger,
489	            &tag,
490	            &options.since,
491	            &options.until,
492	            options.trailing_window,
493	        )?;
494	        Measurement {
495	            self_authored_lines: row.self_authored_lines,
496	            changed_lines: row.changed_lines,
497	            self_authored_commits: row.self_authored_commits,
498	            commits: row.commits,
499	            percentage_basis_points: row.percentage_basis_points,
500	        }
501	    } else {
502	        measure(&options.repo, &options.since, &options.until)?
503	    };
504	    println!(
505	        "{} ({}/{} changed lines; {}/{} commits)",
506	        format_percentage(measurement.percentage_basis_points),
507	        measurement.self_authored_lines,
508	        measurement.changed_lines,
509	        measurement.self_authored_commits,
510	        measurement.commits,
511	    );
512	    Ok(())
513	}
514	
515	fn main() {
516	    if let Err(error) = run() {
517	        eprintln!("self-hosting metric error: {error}");
518	        std::process::exit(1);
519	    }
520	}
