python3 - <<'EOF'
import subprocess,re
def git(*a):
    r=subprocess.run(["git",*a],capture_output=True,text=True)
    if r.returncode: raise RuntimeError(r.stderr[:200])
    return r.stdout
rows=[];cur=None
for line in open("data/meta/self-hosting-ledger.lino"):
    if line.strip()=="release":
        cur={}; rows.append(cur); continue
    m=re.match(r'\s+(\w+) "(.*)"\s*$',line)
    if m and cur is not None: cur[m.group(1)]=m.group(2)

SESSION="formal-ai-session:"; EVID="formal-ai-evidence:"
def trailers(c,k):
    return [l.strip()[len(k):].strip() for l in git("show","-s","--format=%B",c).splitlines()
            if l.strip()[:len(k)].lower()==k and l.strip()[len(k):].strip()]
def attributed(c):
    s=trailers(c,SESSION); e=trailers(c,EVID)
    if not s or not e: return False
    ev=[]
    for p in e:
        try: ev.append(git("show",f"{c}:{p}"))
        except Exception: return False
    if not all("formal-ai" in v.lower() for v in ev): return False
    return all(any(x in v for v in ev) for x in s)
EXCL=("dev/log/",)
LOCK={"Cargo.lock","bun.lock","desktop/bun.lock","vscode/bun.lock","package-lock.json"}
def lines(c,excl):
    t=0
    for line in git("show","--format=","--numstat","--no-renames",c).splitlines():
        f=line.split("\t")
        if len(f)<3 or f[0]=="-" or f[1]=="-": continue
        if excl and (f[2].startswith(EXCL) or f[2] in LOCK): continue
        t+=int(f[0])+int(f[1])
    return t
def bp(n,d): return (n*10000+d//2)//d if d else 0

for excl in (True,):
    out=[]
    for r in rows:
        cs=[c for c in git("rev-list","--reverse","--no-merges",f'{r["since"]}..{r["until"]}').split() if c]
        tot=sa=0;nc=0
        for c in cs:
            n=lines(c,excl); tot+=n
            if attributed(c): sa+=n; nc+=1
        out.append((r["tag"],sa,tot,nc,len(cs)))
    # add pending v0.301.0
    cs=[c for c in git("rev-list","--reverse","--no-merges","v0.300.0..origin/main").split() if c]
    tot=sa=0;nc=0
    for c in cs:
        n=lines(c,excl); tot+=n
        if attributed(c): sa+=n;nc+=1
    out.append(("v0.301.0",sa,tot,nc,len(cs)))
    print(f"{'tag':10} {'self':>7} {'changed':>8} {'pct':>7} {'trail3':>8}")
    for i,(tag,sa,tot,nc,n) in enumerate(out):
        w=out[max(0,i-2):i+1]
        t3=bp(sum(x[1] for x in w),sum(x[2] for x in w))
        print(f"{tag:10} {sa:>7} {tot:>8} {bp(sa,tot)/100:>6.2f}% {t3/100:>7.2f}%   ({nc}/{n} commits)")
EOF

